import React from 'react';
import { withPrefix } from 'gatsby';
import Layout from '../components/Layout';
import { Container } from 'react-bootstrap';
import { StaticImage } from 'gatsby-plugin-image';
import styled from '@emotion/styled';

const WorksWrapper = styled.div`
  padding: 80px 0;
  color: #333;
  font-family: 'Inter', sans-serif;

  h2 {
    font-size: 2.8rem;
    font-weight: 900;
    margin-bottom: 40px;
    display: flex;
    align-items: center;
    gap: 15px;
  }

  h3 {
    font-size: 1.8rem;
    font-weight: 800;
    margin-top: 50px;
    margin-bottom: 20px;
    border-bottom: 1px solid #ddd;
    padding-bottom: 10px;
  }

  .works-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 30px;
    margin-top: 40px;
  }

  .work-item {
    background: #fff;
    border-radius: 12px;
    overflow: hidden;
    box-shadow: 0 10px 30px rgba(0,0,0,0.05);
    transition: transform 0.3s ease;

    &:hover {
      transform: translateY(-5px);
    }

    .work-content {
      padding: 20px;
    }

    h4 {
      font-weight: 700;
      margin-bottom: 10px;
    }

    p {
      color: #666;
      font-size: 0.95rem;
      line-height: 1.6;
      margin-bottom: 20px;
    }

    .video-wrapper {
      width: 100%;
      border-radius: 8px;
      overflow: hidden;
      background: #000;
      aspect-ratio: 16 / 9;
      
      video {
        width: 100%;
        height: 100%;
        object-fit: cover;
      }
    }
  }
`;

const WorksPage = () => {
  return (
    <Layout>
      <Container>
        <WorksWrapper>
          <h2>Works</h2>
          <p>
            これまでに制作したプロジェクトの一覧です。
          </p>

          <div className="works-grid">
            <div className="work-item">
              <div className="work-content">
                <h4>MUROPYON 3D</h4>
                <p>3Dアクションゲームのプロジェクトです。Unreal Engine5を使用して開発されています。</p>
                <div className="video-wrapper">
                  <video autoPlay loop muted playsInline preload="auto" controls>
                    <source src={withPrefix("/videos/muropyon3d.mp4")} type="video/mp4" />
                    Your browser does not support the video tag.
                  </video>
                </div>
              </div>
            </div>
            <div className="work-item">
              <div className="work-content">
                <h4>Zombie Survival</h4>
                <p>サバイバルホラーゲームのプロトタイプです。AIとリソース管理に焦点を当てています。Unreal Engine5を使用して開発されています。</p>
                <div className="video-wrapper">
                  <video autoPlay loop muted playsInline preload="auto" controls>
                    <source src={withPrefix("/videos/zombie_survival.mp4")} type="video/mp4" />
                    Your browser does not support the video tag.
                  </video>
                </div>
              </div>
            </div>
            <div className="work-item">
              <div className="work-content">
                <h4>MUROPYON GAME</h4>
                <p>私が大学二年の時に初めて開発したゲームです。Unityで作られています。レトロスタイルの2Dプラットフォーマーです。ピクセルアートとシンプルな操作性を追求しました。</p>
                <div className="video-wrapper">
                  <video autoPlay loop muted playsInline preload="auto" controls>
                    <source src={withPrefix("/videos/muropyon_game.mp4")} type="video/mp4" />
                    Your browser does not support the video tag.
                  </video>
                </div>
              </div>
            </div>
            <div className="work-item">
              <div className="work-content">
                <h4>学内落とし物アプリ</h4>
                <p style={{ marginBottom: '20px' }}>学内で見つかった落とし物を管理しいつでも見られるようにしたアプリです。貴重品についてはプライバシーに配慮しながら開発しました。</p>
                <div className="video-wrapper" style={{ backgroundColor: '#f0f0f0' }}>
                  <video autoPlay loop muted playsInline preload="auto" controls style={{ objectFit: 'contain' }}>
                    <source src={withPrefix("/videos/otoshimono.mp4")} type="video/mp4" />
                    Your browser does not support the video tag.
                  </video>
                </div>
              </div>
            </div>
            <div className="work-item">
              <div className="work-content">
                <h4>基幹業務アプリ</h4>
                <p style={{ marginBottom: '20px' }}>食品会社にて基幹業務アプリの開発に携わりました。</p>
                <div className="image-wrapper">
                  <StaticImage
                    src="../images/No_Image.png"
                    alt="No Image"
                    placeholder="blurred"
                    layout="constrained"
                    aspectRatio={16 / 9}
                    objectFit="cover"
                  />
                </div>
              </div>
            </div>
            <div className="work-item">
              <div className="work-content">
                <h4>室蘭工業大学 大学祭公式HP</h4>
                <p style={{ marginBottom: '20px' }}>第65回工大祭（室蘭工業大学大学祭）の公式ホームページ制作。デザインから実装まで携わりました。</p>
                <div className="image-wrapper">
                  <a href="https://mit-fes.com/" target="_blank" rel="noopener noreferrer">
                    <StaticImage
                      src="../images/mit_fes.png"
                      alt="室蘭工業大学 大学祭公式HP"
                      placeholder="blurred"
                      layout="constrained"
                      aspectRatio={16 / 9}
                      objectFit="cover"
                    />
                  </a>
                </div>
                <div style={{ marginTop: '10px', textAlign: 'right' }}>
                  <a href="https://mit-fes.com/" target="_blank" rel="noopener noreferrer" style={{ fontSize: '0.85rem', color: '#0044cc' }}>
                    サイトを見る <i className="fas fa-external-link-alt"></i>
                  </a>
                </div>
              </div>
            </div>
            <div className="work-item">
              <div className="work-content">
                <h4>株式会社サンプル コーポレートサイト</h4>
                <p style={{ marginBottom: '20px' }}>ReactとGatsbyを使用したコーポレートサイトの受託開発。SEO対策と高速なページスピードを重視して制作しました。</p>
                <div className="image-wrapper">
                  <StaticImage
                    src="../images/No_Image.png"
                    alt="No Image"
                    placeholder="blurred"
                    layout="constrained"
                    aspectRatio={16 / 9}
                    objectFit="cover"
                  />
                </div>
              </div>
            </div>
          </div>
        </WorksWrapper>
      </Container>
    </Layout>
  );
};

export default WorksPage;
